     5	/// The top-level scene content. Switches between landing / indexing / ready
     6	/// with a shared cross-fade, keeps the grain overlay constant across phases
     7	/// so the warmth is continuous, and hosts the toolbar chrome.
     8	public struct RootScene: View {
     9	
    10	    @Environment(AppModel.self) private var app
    11	
    12	    public init() {}
    13	
    14	    public var body: some View {
    15	        ZStack {
    16	            Palette.canvas.ignoresSafeArea()
    17	            Palette.canvasVignette.ignoresSafeArea().allowsHitTesting(false)
    18	
    19	            content
    20	                .transition(.opacity.combined(with: .scale(scale: 0.992)))
    21	
    22	            NoiseTexture(baseOpacity: 0.032)
    23	                .ignoresSafeArea()
    24	
    25	            if let prompt = app.permissionPrompt {
    26	                PermissionScrim(prompt: prompt)
    27	                    .transition(.opacity)
    28	            }
    29	        }
    30	        .animation(LoomMotion.breathe, value: phaseKey)
    31	        .animation(LoomMotion.breathe, value: app.permissionPrompt)
    32	    }
    33	
    34	    private var phaseKey: String {
    35	        switch app.phase {
    36	        case .landing:  return "landing"
    37	        case .indexing: return "indexing"
    38	        case .ready:    return "ready"
    39	        }
    40	    }
    41	
    42	    @ViewBuilder
    43	    private var content: some View {
    44	        switch app.phase {
    45	        case .landing:
    46	            LandingView()
    47	        case .indexing(let snapshot):
    48	            IndexingView(snapshot: snapshot)
    49	        case .ready:
    50	            WallScene()
    51	        }
    52	    }
    53	}
    54	
    55	/// A dimmed scrim backdrop + centered ``PermissionSheet``. Tapping outside
    56	/// the sheet dismisses; the sheet's own buttons drive the affirmative
    57	/// responses. Posts ``.loomPermissionAllow`` when the user accepts so the
    58	/// coordinator can follow up (trigger the system dialog / re-attempt the
    59	/// library open).
    60	private struct PermissionScrim: View {
    61	    let prompt: PermissionPrompt
    62	    @Environment(AppModel.self) private var app
    63	
    64	    var body: some View {
    65	        ZStack {
    66	            Color.black.opacity(0.45)
    67	                .ignoresSafeArea()
    68	                .onTapGesture { app.dismissPermissionPrompt() }
    69	
    70	            PermissionSheet(
    71	                prompt: prompt,
    72	                onAllow: {
    73	                    NotificationCenter.default.post(
    74	                        name: .loomPermissionAllow, object: prompt
    75	                    )
    76	                    app.dismissPermissionPrompt()
    77	                },
    78	                onDismiss: {
    79	                    app.dismissPermissionPrompt()
    80	                }
    81	            )
    82	            .transition(.scale(scale: 0.96).combined(with: .opacity))
    83	        }
    84	    }
    85	}
