{"content":"     1	import SwiftUI
     2	
     3	/// A small shadow library. Light canvases are trickier than dark: pure-black
     4	/// shadows on cream read as dirty. Loom uses warm near-black at low alpha so
     5	/// the shadow registers as *paper lifted off paper*, not as a digital drop
     6	/// shadow.
     7	public enum LoomShadow {
     8	
     9	    /// Warm near-black used across every shadow in the app. Avoids the
    10	    /// "printed photo cutout" effect that pure black gives on cream.
    11	    public static let tone = Color(red: 0.15, green: 0.11, blue: 0.08)
    12	
    13	    /// For tiles on the canvas. Soft, warm, minimal offset — photos should
    14	    /// look like they're resting on the paper, not floating above it.
    15	    public struct Tile: ViewModifier {
    16	        public func body(content: Content) -> some View {
    17	            content
    18	                .shadow(color: LoomShadow.tone.opacity(0.09), radius: 14, x: 0, y: 6)
    19	                .shadow(color: LoomShadow.tone.opacity(0.05), radius: 2,  x: 0, y: 1)
    20	        }
    21	    }
    22	
    23	    /// For elevated surfaces — popovers, the command palette, permission
    24	    /// sheets.
    25	    public struct Surface: ViewModifier {
    26	        public func body(content: Content) -> some View {
    27	            content
    28	                .shadow(color: LoomShadow.tone.opacity(0.15), radius: 28, x: 0, y: 14)
    29	                .shadow(color: LoomShadow.tone.opacity(0.08), radius: 3,  x: 0, y: 2)
    30	        }
    31	    }
    32	
    33	    /// For the primary CTA — a subtle terracotta halo so the button feels
    34	    /// warm.
    35	    public struct Brass: ViewModifier {
    36	        public func body(content: Content) -> some View {
    37	            content
    38	                .shadow(color: Palette.brass.opacity(0.22), radius: 14, x: 0, y: 0)
    39	                .shadow(color: LoomShadow.tone.opacity(0.14), radius: 6, x: 0, y: 3)
    40	        }
    41	    }
    42	}
    43	
    44	public extension View {
    45	    func tileShadow()    -> some View { modifier(LoomShadow.Tile()) }
    46	    func surfaceShadow() -> some View { modifier(LoomShadow.Surface()) }
    47	    func brassShadow()   -> some View { modifier(LoomShadow.Brass()) }
    48	}
